/**
 * Records all calls to Core WASM/`CoreBridge`
 * To use this, set to `true` or call `await instance._store.getState().backend.client.enableCoreCallRecording(true)`
 * Whenever you want to see the calls, you can:
 * - Check the `CALL_RECORDINGS` array OR
 * - Call `await instance._store.getState().backend.client.getCoreCallRecording()` in the console
 */
let RECORD_CALLS = false

enum CallRecordingType {
  Daemon,
  WASM,
}

type CallRecording = {
  type: CallRecordingType
  name: string
  args: unknown[]
  time: number
}
const CALL_RECORDINGS: CallRecording[] = []

function shouldStringify(arg) {
  return arg != null && arg.length != null && arg.length === 0
}

