  async load(
    _baseCoreUrl: string,
    licenseKey: string | undefined | null,
    {
      mainThreadOrigin,
      customFonts,
      dynamicFonts,
      productId,
    }: {
      mainThreadOrigin: string
      customFonts?: Array<FetchedCustomFont> | Array<FetchedNodeCustomFont>
      dynamicFonts?: string | null
      productId: IProductId | null
    },
  ): Promise<LoadResponse | void> {
    invariant(_module, ERROR_MODULE_NOT_LOADED)

    let rawResult

    try {
      if (!_module.FS.analyzePath(fontsPath).exists) {
        _module.FS.mkdir(fontsPath)
      }

      customFontsPath = customFonts ? `${fontsPath}/custom-fonts` : ''

      if (customFonts && !_module.FS.analyzePath(customFontsPath).exists) {
        mountCustomFonts(customFonts, customFontsPath)
      }

      if (isElectron()) {
        invariant(
          productId == null || productId === ProductId.Electron,
          `PSPDFKit is running on Electron, but has been setup to be used with ${productId}` +
            'Please contact support to resolve the issue.',
        )
        productId = ProductId.Electron
      }

      rawResult = _module.initPSPDFKit(
        licenseKey == null ? '' : licenseKey,
        mainThreadOrigin,
        fontsPath,
        '',
        // app-id: "", 'SPO' for SharePoint Online, or 'SF' for Salesforce
        productId && typeof productIdMapping[productId] !== 'undefined'
          ? productIdMapping[productId]
          : '',
      )

      if (dynamicFonts) {
        const dynamicFontsJSON = await downloadDynamicFontsFile(dynamicFonts)

        daemonExec(
          'dynamic_font_loading/set_metadata_file',
          undefined,
          await dynamicFontsJSON.arrayBuffer(),
        )

        dynamicFontsBaseURL = dynamicFonts.split('/').slice(0, -1).join('/')
      }
    } catch (error) {
      throw error
    }

    const result = JSON.parse(rawResult)

    if (initTimer) {
      log(`Native initialization complete, took: ${Date.now() - initTimer}ms`)
    }

    if (!result.success) {
      throw new Error('Failed to initialize PSPDFKit: ' + result.error)
    }

    return result
  }

