  async getAvailableFontFaces(
    customFonts: FetchedCustomFont[] | undefined,
  ): Promise<ReadableCustomFont[]> {
    if (!customFonts) {
      return []
    }

    const fontsResult = daemonExec('get_available_font_faces')

    return fontsResult[0]?.font_faces.reduce((acc, readableFont) => {
      const providedCustomFont = customFonts.find(
        customFont => customFont.name === readableFont.path.replace(`${customFontsPath}/`, ''),
      )

      if (providedCustomFont) {
        return acc.concat({
          readableName: readableFont.fullName,
          name: providedCustomFont.name,
        })
      }

      return acc
    }, [] as ReadableCustomFont[])
  }

