  async openAndReturnDocumentInfo(initialPageIndex?: number): Promise<DocumentResponse> {
    exec(
      'openDocument',
      CREATE_FILE_PATH,
      JSON.stringify({
        password,
      }),
    )

    if (isJavaScriptSupportEnabled) {
      enablePDFJavaScriptSupport()
    }

    exec('automaticLinkExtraction', enableAutomaticLinkExtraction)

    const documentInfo = exec('getDocumentInfo').documentInfo

    // Return early if we have no pages in the document.
    if (documentInfo.pageCount <= 0) {
      return documentInfo
    }

    let pages: PageInfoResponse[] = []

    if (typeof initialPageIndex === 'number') {
      const firstPageInfo = await this.getPageInfo(initialPageIndex)

      // We assign all the pages with the info from the first page to set some initial values quickly.
      // These are a best guess, and will be updated in a lazy way on the next query.
      for (let index = 0; index < documentInfo.pageCount; index++) {
        const pageInfo = {
          ...firstPageInfo,
          pageIndex: index,
          pageLabel: initialPageIndex === index ? firstPageInfo.pageLabel : String(index + 1),
        }
        pages.push(pageInfo)
      }
    } else {
      pages = await this.getAllPageInfos(documentInfo.pageCount)
    }

    documentInfo.pages = pages

    return documentInfo
  }

  async getPageInfo(pageIndex: number): Promise<PageInfoResponse> {
    try {
      const pageInfoResult = daemonExec('page_info', {
        query: 'page_info',
        page: pageIndex,
      })

      invariant(
        pageInfoResult.length === 1,
        'expected page_info result to return 1 result when specifying index.',
      )

      const jsonString = new TextDecoder().decode(pageInfoResult[0])
      const parsedData = JSON.parse(jsonString)

      return parsedData.pageInfo
    } catch (e) {
      error(
        `Dimensional information for page ${pageIndex} unavailable, page will not be displayed.`,
      )
      const pageInfo: PageInfoResponse = {
        height: 0,
        matrix: [0, 0, 0, 0, 0, 0],
        pageLabel: '',
        reverseMatrix: [0, 0, 0, 0, 0, 0],
        transformedBBox: [0, 0, 0, 0],
        untransformedBBox: [0, 0, 0, 0],
        width: 0,
        pageIndex,
        rawPdfBoxes: {
          bleedBox: null,
          cropBox: null,
          mediaBox: null,
          trimBox: null,
        },
      }

      return pageInfo
    }
  }

  /**
   * Check if Core can render the annotation with the provided text.
   */
  async preflightRenderAnnotationText(
    text: string,
    pdfObjectId?: number,
    page?: number,
    annotation?: AnnotationBackendJSON,
  ): Promise<void> {
    const callPreflight = () => {
      if (typeof pdfObjectId === 'number' && typeof page === 'number') {
        return daemonExec('dynamic_font_loading/preflight_annotation', {
          text,
          annotation_id: pdfObjectId,
          page,
        })[0]
      } else {
        invariant(annotation, `annotation not set: ${annotation}`)

        return daemonExec('dynamic_font_loading/preflight_annotation', {
          text,
          annotation_json: annotation as AnnotationJSONUnion,
        })[0]
      }
    }

    try {
      let result: PreflightAnnotationResponse = callPreflight()

      if (result.preflight_result === PreflightAnnotationResult.requiresMoreFonts) {
        await this.addDynamicFonts(result.required_fonts as string[])

        result = callPreflight()
      }

      if (typeof pdfObjectId === 'number') {
        if (result.preflight_result === PreflightAnnotationResult.unableToShape) {
          nonRenderablePdfObjectIds.add(pdfObjectId)
        } else {
          nonRenderablePdfObjectIds.delete(pdfObjectId)
        }
      }
    } catch (e) {
      error(
        `There was an error testing rendering for annotation ${pdfObjectId} of this text: ${text}: ${e.message}`,
      )
    }
  }

  async addDynamicFonts(fonts: string[]) {
    let fontsToLoad: string[] = []

    try {
      fontsToLoad = fonts.filter(font => {
        if (loadedFonts.has(font)) {
          return false
        }

        return true
      })

      const fontsBuffers = await Promise.all(
        fontsToLoad.map(font =>
          fetch(`${dynamicFontsBaseURL}/${font}`).then(res => res.arrayBuffer()),
        ),
      )

      addFonts(
        fontsBuffers.map((buffer, fontsIndex) => ({
          name: fontsToLoad[fontsIndex],
          data: buffer,
        })),
      )

      fontsToLoad.forEach(font => {
        loadedFonts.add(font)
      })
    } catch (e) {
      fontsToLoad.forEach(font => {
        loadedFonts.delete(font)
      })

      error(`There was an error loading a font: ${e}`)
    }

    await daemonExec('dynamic_font_loading/notify_fonts_added', {
      added_fonts: fontsToLoad.map(font => ({
        remote_file_path: font,
        local_file_name: font,
      })),
    })
  }

  /**
   * Get page information for all the pages of the document.
   */
  async getAllPageInfos(pageCount: number): Promise<Array<PageInfoResponse>> {
    const pages: PageInfoResponse[] = []

    try {
      const pageInfosResult = daemonExec('page_info', {
        query: 'page_info',
        page: 'all',
      })

      invariant(
        pageInfosResult.length === pageCount,
        'expected the same length of page info response to page count.',
      )

      for (let i = 0; i < pageInfosResult.length; i++) {
        const jsonString = new TextDecoder().decode(pageInfosResult[i])
        const parsedData = JSON.parse(jsonString)
        pages.push(parsedData.pageInfo)
      }
    } catch (e) {
      error(
        'There was an error retrieving page information for all pages from core. Reverting to individual queries.',
      )

      for (let index = 0; index < pageCount; index++) {
        try {
          const pageInfoResult = daemonExec('page_info', {
            query: 'page_info',
            page: index,
          })

          invariant(
            pageInfoResult.length === 1,
            'expected page_info result to return 1 result when specifying index.',
          )

          const jsonString = new TextDecoder().decode(pageInfoResult[0])
          const parsedData = JSON.parse(jsonString)
          pages.push(parsedData.pageInfo)
        } catch (e) {
          error(
            `Dimensional information for page ${index} unavailable, page will not be displayed.`,
          )
          const pageInfo: PageInfoResponse = {
            height: 0,
            matrix: [0, 0, 0, 0, 0, 0],
            pageLabel: '',
            reverseMatrix: [0, 0, 0, 0, 0, 0],
            transformedBBox: [0, 0, 0, 0],
            untransformedBBox: [0, 0, 0, 0],
            width: 0,
            pageIndex: index,
            rawPdfBoxes: {
              bleedBox: null,
              cropBox: null,
              mediaBox: null,
              trimBox: null,
            },
          }
          pages.push(pageInfo)
        }
      }
    }

    return pages
  }

