  async setFormValues(values: Array<FormFieldValueJSON>): Promise<void> {
    const formFieldsAndWidgets = readFormJSONObjects()

    let haveValuesChanged = false

    const widgetsToPreflight: {
      widgets: AnnotationBackendJSON<WidgetAnnotationJSON>[]
      text: string
    }[] = []

    const newFormFieldsAndWidgets = formFieldsAndWidgets.map(formFieldWithWidgets => {
      const value = values.find(v => v.name === formFieldWithWidgets.formField.name)

      if (value) {
        // Do not update the value if it has not changed.
        if (
          value.value === formFieldWithWidgets.value ||
          (Array.isArray(value.value) &&
            Array.isArray(formFieldWithWidgets.value) &&
            value.value.every((v, i) => v === (formFieldWithWidgets.value as Array<string>)[i]))
        ) {
          return formFieldWithWidgets
        }

        if (typeof value.value === 'string' && value.value.length > 0) {
          widgetsToPreflight.push({
            widgets: formFieldWithWidgets.widgets,
            text: value.value,
          })
        } else {
          formFieldWithWidgets.widgets.forEach(widget => {
            if (typeof widget.pdfObjectId === 'number') {
              nonRenderablePdfObjectIds.delete(widget.pdfObjectId)
            }
          })
        }

        haveValuesChanged = true

        return {
          ...formFieldWithWidgets,
          value: value.value,
        }
      }

      return formFieldWithWidgets
    })

    // Only apply the changes if there are changes to the values.
    if (haveValuesChanged) {
      if (dynamicFontsBaseURL) {
        for (let i = 0; i < widgetsToPreflight.length; i++) {
          const widgets = widgetsToPreflight[i].widgets

          for (let j = 0; j < widgets.length; j++) {
            await this.preflightWidgetAnnotation(
              widgets[j] as AnnotationBackendJSON<WidgetAnnotationJSON>,
              widgets[j].pdfObjectId,
              widgetsToPreflight[i].text,
            )
          }
        }
      }

      applyFormJSONObjects(newFormFieldsAndWidgets)
    }
  }

