  async prepareSign(
    signerDataSource: SignerDataSourceJSON,
    signatureMetadata: SignatureMetadata | null,
    flatten: boolean,
    formFieldName: string | undefined,
    signaturePosition: SignaturePositionJSON | null,
    signatureAppearance: SignatureAppearanceJSON | null,
  ): Promise<SignaturePreparedData> {
    let signaturesInfo
    const applyRedactions = false
    const saveForPrinting = false
    const targetFormat = 'pdf'

    try {
      signaturesInfo = daemonExec('get_signatures', {
        certificate_check_time: 'current_time',
      })[0]

      // Save backup file.
      const flatten = false
      // We need to save incrementally in order not to corrupt previous signatures.
      const incremental = signaturesInfo.status !== 'not_signed'

      exec(
        'saveDocument',
        SAVE_FILE_PATH,
        flatten,
        incremental,
        applyRedactions,
        saveForPrinting,
        targetFormat,
        false,
      )
      exec(
        'openDocument',
        SAVE_FILE_PATH,
        JSON.stringify({
          password,
        }),
      )
    } catch (error) {
      throw new Error(`Error saving document backup for invisible signing: ${error}`)
    }

    try {
      // Save file for signing preparation.
      // Flattening the document wipes out any previous signature. We only want to
      // keep previous signatures if the document is not meant to be flattened when signed.
      // We only need to save incrementally if there are previous signatures so as not to corrupt them,
      // unless the document is meant to be flattened in the signing process.
      const incremental = !flatten && signaturesInfo.status !== 'not_signed'

      exec(
        'saveDocument',
        CREATE_FILE_PATH,
        flatten,
        incremental,
        applyRedactions,
        saveForPrinting,
        targetFormat,
        false,
      )

      // If the document is to be flattened, we need to open it so the current document is flattened.
      if (flatten) {
        exec(
          'openDocument',
          CREATE_FILE_PATH,
          JSON.stringify({
            password,
          }),
        )

        if (isJavaScriptSupportEnabled) {
          enablePDFJavaScriptSupport()
        }
      }
    } catch (error) {
      throw new Error(`Error saving document for invisible signing: ${error}`)
    }

    let result

    try {
      result = daemonExec('prepare_sign', {
        signer_data_source: {
          ...signerDataSource,
          field_name: formFieldName,
          position: signaturePosition,
          appearance: signatureAppearance,
          type: 'pspdfkit/signer-data-source',
        },
        signature_metadata: {
          ...signatureMetadata,
          type: 'pspdfkit/signature-metadata',
        },
      })
    } catch (error) {
      throw new Error(`Error preparing document for signing: ${error}`)
    }

    invariant(_module, ERROR_MODULE_NOT_LOADED)

    let fileContents = null

    if (!signerDataSource || signerDataSource?.signatureType === SignatureTypeJSON.cms) {
      fileContents = _module.FS.readFile(result[0].result.file_contents).buffer
    }

    // After Core returns this temp file it no longer needs it
    _module.FS.unlink(result[0].result.file_contents)

    return {
      file: result[0].result.file,
      hash: result[0].result.hash,
      signatureFormFieldName: result[0].result.signature_form_fqn,
      dataToBeSigned: result[0].result.data_to_be_signed,
      fileContents,
    }
  }

