  async compareDocuments(comparisonConfig: ComparisonConfig): Promise<DocumentComparisonResult> {
    try {
      invariant(
        comparisonConfig.originalDocument.arrayBuffer,
        'Original document arrayBuffer is missing',
      )
      invariant(
        comparisonConfig.changedDocument.arrayBuffer,
        'Changed document arrayBuffer is missing',
      )

      // Write the buffers to the filesystem so that the daemon can access them
      _module.FS.writeFile(
        'documentA.pdf',
        new Uint8Array(comparisonConfig.originalDocument.arrayBuffer),
      )
      _module.FS.writeFile(
        'documentB.pdf',
        new Uint8Array(comparisonConfig.changedDocument.arrayBuffer),
      )

      // Update the comparison config with the paths to the documents
      const updatedComparisonConfig = {
        originalDocument: {
          ...comparisonConfig.originalDocument,
          filePath: 'documentA.pdf',
        },
        changedDocument: {
          ...comparisonConfig.changedDocument,
          filePath: 'documentB.pdf',
        },
        comparisons: [comparisonConfig.comparisonOperation],
      }

      const result = daemonExec('document_comparison', updatedComparisonConfig)

      return result || null
    } catch (error) {
      throw new Error(`Error comparing documents: ${error.message}`)
    }
  }

