  async exportFile(
    flatten: boolean,
    incremental: boolean,
    saveForPrinting: boolean,
    format: string,
    excludeAnnotations: boolean,
    preserveInstantJSONChanges: boolean,
    permissions?: {
      userPassword: string
      ownerPassword: string
      documentPermissions: Array<IDocumentPermissions>
    },
    signatureWidgetsToFlatten?: FlattenElectronicallySignedFormFieldsPayload,
  ): Promise<[ArrayBuffer, ExportFileFormat]> {
    let formatInfo = {
      mimeType: 'application/pdf',
      extension: 'pdf',
    }
    let results

    try {
      const applyRedactions = false

      results = daemonExec('save_document', {
        file_path: CREATE_FILE_PATH,
        format,
        flatten_annotations: flatten,
        save_incrementally: incremental,
        apply_redactions: applyRedactions,
        save_for_printing: saveForPrinting,
        remove_all_annotations: excludeAnnotations,
        preserve_change_tracker_state: preserveInstantJSONChanges,
        ...(permissions
          ? {
              user_password: permissions.userPassword,
              owner_password: permissions.ownerPassword,
              document_permissions: mapToCorePermissions(permissions.documentPermissions),
            }
          : null),
      })

      if (signatureWidgetsToFlatten) {
        signatureWidgetsToFlatten.forEach(({ pageIndex, id, pdfObjectId }) => {
          daemonExec('electronic_signatures/flatten', {
            page: pageIndex,
            annotation_id: this._getPdfObjectIdForObject({ id, pdfObjectId }),
          })
        })

        results = daemonExec('save_document', {
          file_path: SAVE_FILE_PATH,
          format,
          flatten_annotations: flatten,
          save_incrementally: incremental,
          apply_redactions: applyRedactions,
          save_for_printing: saveForPrinting,
          remove_all_annotations: excludeAnnotations,
          preserve_change_tracker_state: preserveInstantJSONChanges,
          ...(permissions
            ? {
                user_password: permissions.userPassword,
                owner_password: permissions.ownerPassword,
                document_permissions: mapToCorePermissions(permissions.documentPermissions),
              }
            : null),
        })
      }
    } catch (error) {
      throw new Error(`Error saving to ${SAVE_FILE_PATH}: ${error.message}`)
    }

    const result = results[0]

    if (result.format) {
      formatInfo = {
        mimeType: result.format.mime_type,
        extension: result.format.extension,
      }
    }

    invariant(_module, ERROR_MODULE_NOT_LOADED)

    const fileBuffer = _module.FS.readFile(
      signatureWidgetsToFlatten ? SAVE_FILE_PATH : CREATE_FILE_PATH,
    ).buffer

    if (signatureWidgetsToFlatten) {
      exec('closeDocument')
      exec(
        'openDocument',
        CREATE_FILE_PATH,
        JSON.stringify({
          password,
        }),
      )
    }

    return [fileBuffer, formatInfo]
  }

