  // Document comparison methods
  comparisonDocuments: Record<string, ArrayBuffer> = {}
  lastOpenedComparisonDocument: DocumentComparisonDocumentKey | null = null

  async setComparisonDocument(
    documentKey: DocumentComparisonDocumentKey,
    buffer: ArrayBuffer | null,
  ): Promise<void> {
    this.comparisonDocuments[documentKey] =
      buffer || (await this.exportFile(false, false, false, 'pdf', false, false))[0]
  }

  async openComparisonDocument(
    documentKey: DocumentComparisonDocumentKey,
  ): Promise<DocumentResponse | null> {
    invariant(this.comparisonDocuments[documentKey])

    if (
      documentKey === this.lastOpenedComparisonDocument ||
      (documentKey === DOCUMENT_KEY.documentA &&
        this.lastOpenedComparisonDocument === null &&
        this.persistedOpenDocument instanceof ArrayBuffer)
    ) {
      return null
    }

    this.lastOpenedComparisonDocument = documentKey

    return this.openDocument(
      this.comparisonDocuments[documentKey],
      this.persistedOpenDocument === documentKey ? this.persistedOpenDocumentPassword : undefined,
    )
  }

  async documentCompareAndOpen(
    settings: DocumentComparisonConfigurationJSON,
  ): Promise<DocumentResponse> {
    invariant(
      this.comparisonDocuments[DOCUMENT_KEY.documentA] &&
        this.comparisonDocuments[DOCUMENT_KEY.documentB],
      'One or both comparison input documents are missing.',
    )

    const documentAFileName = `${DOCUMENT_KEY.documentA}.pdf`
    const documentBFileName = `${DOCUMENT_KEY.documentB}.pdf`

    _module.FS.writeFile(
      documentAFileName,
      new Uint8Array(this.comparisonDocuments[DOCUMENT_KEY.documentA]),
    )
    _module.FS.writeFile(
      documentBFileName,
      new Uint8Array(this.comparisonDocuments[DOCUMENT_KEY.documentB]),
    )

    const preparedSettings = {
      documentA: {
        strokeColor: settings.documentA.strokeColor,
        pageIndex: settings.documentA.pageIndex,
        filePath: documentAFileName,
      },
      documentB: {
        strokeColor: settings.documentB.strokeColor,
        pageIndex: settings.documentB.pageIndex,
        filePath: documentBFileName,
      },
      options: {
        ...settings.options,
        outputFilePath: 'output.pdf',
      },
    }

    daemonExec('comparison', preparedSettings)

    await this.closeDocument()

    this.comparisonDocuments[DOCUMENT_KEY.result] = _module.FS.readFile('output.pdf').buffer

    this.lastOpenedComparisonDocument = DOCUMENT_KEY.result

    return this.openDocument(this.comparisonDocuments[DOCUMENT_KEY.result], undefined)
  }

  persistedOpenDocument: DocumentComparisonDocumentKey | ArrayBuffer | null = null
  persistedOpenDocumentPassword: string | undefined | null

  async persistOpenDocument(documentKey: DocumentComparisonDocumentKey | undefined): Promise<void> {
    if (documentKey) {
      this.persistedOpenDocument = documentKey
    } else {
      try {
        this.persistedOpenDocument = (
          await this.exportFile(false, false, false, 'pdf', false, true)
        )[0]
      } catch (error) {
        throw new Error(
          `Error trying to persist a copy of the currently opened document: ${error.message}`,
        )
      }
    }

    this.persistedOpenDocumentPassword = password
  }

  async cleanupDocumentComparison(): Promise<DocumentResponse> {
    invariant(
      this.persistedOpenDocument,
      'No persisted previous document key or array buffer is available.',
    )

    const persistedDocumentArrayBuffer =
      this.persistedOpenDocument instanceof ArrayBuffer
        ? this.persistedOpenDocument
        : this.comparisonDocuments[this.persistedOpenDocument]

    invariant(persistedDocumentArrayBuffer, 'No persisted previous array buffer is available.')

    try {
      await this.closeDocument()
    } catch (error) {
      throw new Error(`Error trying to close the current document: ${error.message}`)
    }

    const openDocumentPromise = this.openDocument(
      persistedDocumentArrayBuffer,
      this.persistedOpenDocumentPassword,
    )

    this.persistedOpenDocument = null
    this.persistedOpenDocumentPassword = null
    this.lastOpenedComparisonDocument = null

    this.comparisonDocuments = {}

    return openDocumentPromise
  }

  // We do not pass new annotation's and form field's pdfObjectId's to the front end, but persist them
  // in a local object, from where we retrieve them when needed (when updating and deleting).
  _getPdfObjectIdForObject(
    object: AnnotationsBackendJSONUnion | FormFieldJSON | TabOrderIdsEntry,
  ): number {
    // The object can have a pdfObjectId if it comes from the original document.
    if (typeof object.pdfObjectId === 'number') {
      return object.pdfObjectId
    } else {
      // If it isn't, retrieve the mapped pdfObjectId
      return this._pdfObjectIdsForIds[object.id]
    }
  }

