import { invariant } from '@pspdfkit/shared'

export default function isomorphicRequireBrowser(
  url: string,
): Promise<(...args: Array<any>) => any> {
  if (typeof window === 'object') {
    // In a browser, we have to create a new <script> tag.
    return new Promise((resolve, reject) => {
      const script = document.createElement('script')

      script.type = 'text/javascript'
      script.async = true

      script.onload = () => resolve((<any>window).PSPDFModuleInit)

      script.onerror = reject
      script.src = url

      const { documentElement } = document

      invariant(documentElement)

      documentElement.appendChild(script)
    })
  } else {
    // In a webworker environment, we use `importScripts`. We assume that the module is exported
    // as `self.Module`.
    ;(<any>self).importScripts(url)

    return Promise.resolve((<any>self).PSPDFModuleInit)
  }
}
