/**
 * Helper functions for running PSPDFKit for Web inside Electron.
 */
import { error } from '@pspdfkit/shared'

/**
 * Detects an electron instance. In the remaining code, it will identify itself as a blink system
 * so chrome related workarounds will still apply. This utility is mainly used for Electron specific
 * features and licensing.
 *
 * c.f. https://github.com/electron/electron/issues/2288
 *
 * It relies exclusively on the user agent string, so customers spoofing it in their Electron apps
 * may find errors when Core identifies the bundle ID as PSPDFKit for Web and not Electron.
 *
 * We cannot rely on the availability of Node APIs because they're not present when using
 * Electron with context isolation, which is the recommended configuration.
 */
export function isElectron(): boolean {
  // Parse the user agent string
  if (
    typeof navigator === 'object' &&
    typeof navigator.userAgent === 'string' &&
    navigator.userAgent.indexOf('Electron/') >= 0
  ) {
    return true
  }

  return false
}

/**
 * There are two modes of use within Electron:
 *
 * 1. The legacy, insecure, old way, which makes use of node integration and
 * enables directly accessing the node API from the browser context and thus
 * is not compatible with context isolation.
 *
 * 2. The new, recommended way which only exposes the required, specified Node
 * methods through contextBridge in a preload script, and provides no direct access
 * to require().
 *
 * This functiion returns true only for the first case (Electron with node integration enabled).
 */
export function isElectronWithNodeIntegration() {
  const global = getGlobal()
  // The require() reference needs to be obfuscated to prevent Webpack from transpiling it
  // for the browser; here it's base64'ed.
  const require = global[atob('cmVxdWlyZQ==')]

  // Recommended feature detection, won't work in a WebWorker
  return (
    isElectron() &&
    typeof window !== 'undefined' &&
    window &&
    window.process &&
    // @ts-expect-error
    window.process.type &&
    typeof require === 'function'
  )
}

/**
 * This helper requires the available remote module handler when using Electron.
 *
 * Remote modules are handled by different modules depending on the Electron version.
 * - Until Electron 10, only the built-in electron.remote module was available.
 * - From Electron 10 onwards, the @electron/remote is the preferred approach.
 * - Electron 14 removes the built-in electron.remote module and makes @electron/remote,
 * which now needs to be added as a dependency, the only way to use remote modules in the renderer process.
 *
 * This helper tries to load the @electron/remote module, otherwise falls back to the built-in electron.remote.
 * If none are available, it throws.
 *
 * There is currently no way to use PSPDFKit for Web in Electron without enabling remote modules in the application,
 * which means context isolation must be disabled, and node integration enabled. The reason is that, for now,
 * there's no other logic in place to check the app name nor, consequently, the license ID.
 *
 * We want to solve this in the future, so the SDK can be used in Electron with context isolation and without node integration,
 * for enhanced security, as demanded by some customers.
 */
function requireElectronRemote() {
  let electronRemote

  try {
    electronRemote = requireAtRuntime('@electron/remote')
  } catch (e1) {
    if (e1.code === 'MODULE_NOT_FOUND') {
      try {
        electronRemote = requireAtRuntime('electron').remote
      } catch (e2) {
        error(
          `Failed to load the remote module package. PSPDFKit for Web needs access to it in order to work in Electron.
        Please read our Electron guides to help you set it up: https://pspdfkit.com/getting-started/electron/
        ${e1.message}
        ${e2.message}`,
        )
      }
    } else {
      throw e1
    }
  }

  return electronRemote
}

// Get app name (=bundle ID) from the Electron remote module,
// only when using Electron with node integration. When using
// Electron with context isolation (=without node integration)
// the app name is provided by the customer in Configuration.appName.
export function getElectronAppId(): string | null | undefined {
  if (!isElectron()) {
    return null
  }

  if (!isElectronWithNodeIntegration()) {
    return null
  }

  try {
    const fs = requireAtRuntime('fs')
    const electronRemote = requireElectronRemote()
    const packagePath = electronRemote.app.getAppPath() + '/package.json'
    const packageObject = JSON.parse(fs.readFileSync(packagePath).toString())

    return packageObject.name
  } catch (error) {
    throw new Error(`There was an error parsing this project's \`package.json\`: ${error.message}`)
  }
}

export function getElectronBaseUrl(): string | null | undefined {
  if (!isElectron()) {
    return null
  }

  try {
    const electronRemote = requireElectronRemote()

    return `file://${electronRemote.app.getAppPath()}/node_modules/pspdfkit/dist/`
  } catch (error) {
    return null
  }
}

// We need to hide the call to `require()` since webpack would transpile it to the project build
// time require environment.
export function requireAtRuntime(moduleName: string): any {
  const global = getGlobal()
  const require = global[atob('cmVxdWlyZQ==')]

  return require(moduleName)
}

function getGlobal() {
  if (typeof window !== 'undefined') {
    return window
  } else if (typeof self !== 'undefined') {
    return self
  } else {
    return global
  }
}
