import isomorphicRequireNode from './isomorphicRequireNode'
import isomorphicRequireBrowser from './isomorphicRequireBrowser'

let isomorphicRequire: typeof isomorphicRequireNode | typeof isomorphicRequireBrowser

if (
  typeof process === 'object' &&
  typeof process.versions === 'object' &&
  typeof process.versions.node !== 'undefined'
) {
  isomorphicRequire = isomorphicRequireNode
} else {
  isomorphicRequire = isomorphicRequireBrowser
}

export default isomorphicRequire
