// @ts-expect-error
import WASM_CHECKSUM from '@pspdfkit/checksum-loader!@/../vendor/pspdfkit.wasm'
// @ts-expect-error
import WASM_JS_CHECKSUM from '@pspdfkit/checksum-loader!@/../vendor/pspdfkit.wasm.js'
import { error, log, warn } from '@pspdfkit/shared'

import isomorphicRequire from './isomorphicRequire'

const isBundled = process.env.NODE_ENV !== 'test'
const isProduction = process.env.NODE_ENV === 'production'
const addHash = isBundled && isProduction
const LIB_DIR = isBundled ? `${PSPDFKIT_DEFINES.BUNDLE}/` : ''
const WASM_INIT_FILE = `${LIB_DIR}pspdfkit${addHash ? '-' + WASM_JS_CHECKSUM : ''}.wasm.js`
const WASM_FILE = `${LIB_DIR}pspdfkit${addHash ? '-' + WASM_CHECKSUM : ''}.wasm`

/**
 * Loads and initializes a native module
 *
 * We need to wrap the resolved module into a new object since the native module defines a `then`
 * property which would otherwise never resolve.
 */
export function loadNativeModule(
  baseCoreUrlOrWasmPath: string | { wasmLoaderPath: string; wasm: ArrayBuffer },
  disableWebAssemblyStreaming: boolean,
  global: typeof globalThis = globalThis,
): Promise<{
  nativeModule: Record<string, any>
}> {
  let initialModule: {
    wasmBinaryFile: string
    locateFile: (file: string) => string
    wasmBinary: any
  }

  let factory: (...args: any[]) => any

  // eslint-disable-next-line no-async-promise-executor
  return new Promise(async resolve => {
    initialModule = initializeModule(baseCoreUrlOrWasmPath, disableWebAssemblyStreaming)

    if (typeof baseCoreUrlOrWasmPath === 'string') {
      const baseCoreUrl = baseCoreUrlOrWasmPath
      factory = await isomorphicRequire(`${baseCoreUrl}${WASM_INIT_FILE}`)
    } else if (process.env.BACKEND_BUILD === 'true' || process.env.NODE_ENV === 'test') {
      factory = (await import(baseCoreUrlOrWasmPath.wasmLoaderPath)).default
    }

    log('Using WASM method')
    injectRequiredGlobals(global)

    // In a browser environment, initializing the module is asynchronous and thus we have to wait
    // for the _Main method in the initialized module to be called
    const nativeModule = await factory(initialModule)

    resolve({
      nativeModule,
    })
  })
}

/**
 * The Module is the global injection point for the native WASM/ASM.js libraries.
 *
 * We explicity force the type to `any` since the native modules will also inject
 * their API here and we want to call them
 */
export function initializeModule(
  baseCoreUrlOrWasmPath: string | { wasmLoaderPath: string; wasm: ArrayBuffer },
  disableWebAssemblyStreaming: boolean,
) {
  // Specifying the `wasmBinary` prevents the `pspdfkit.wasm.js` from trying to
  // load it from a URL.
  let wasmBinary

  if (typeof baseCoreUrlOrWasmPath === 'object') {
    wasmBinary = baseCoreUrlOrWasmPath.wasm

    const module = {
      // We manually set the WASM binary file path so we can append baseUrl properly
      wasmBinaryFile: WASM_FILE,
      // Rename the memory initializer filename
      locateFile: (file: string) => file,
      wasmBinary: wasmBinary,
    }

    return module
  } else if (process.env.NODE_ENV === 'test' || process.env.BACKEND_BUILD === 'true') {
    const fs = require('fs')

    const buf = fs.readFileSync('./vendor/pspdfkit.wasm')

    wasmBinary = buf
  }

  const baseUrl = baseCoreUrlOrWasmPath

  const module = {
    // We manually set the WASM binary file path so we can append baseUrl properly
    wasmBinaryFile: baseUrl + WASM_FILE,
    // Rename the memory initializer filename
    locateFile: (file: string) => file,
    wasmBinary: wasmBinary,
  }

  // To include the HTTP authentication headers in a browser environment, we have to patch the
  // binary load methods of Emscripten.
  if (process.env.NODE_ENV !== 'test' && process.env.BACKEND_BUILD !== 'true') {
    // For WASM, we can write a custom instantiate method.
    // https://emscripten.org/docs/api_reference/module.html#Module.instantiateWasm
    const fetchPromise = fetch(module.wasmBinaryFile, {
      credentials: 'same-origin',
    })

    const uncompressedFileSize = PSPDFKIT_DEFINES.WASM_FILESIZE as number

    fetchPromise
      .then(response => {
        const contentLength = response.headers.get('content-length')

        // Content-Length may not be set when using HTTP 1.1 Transfer-Encoding
        // chunked. In this case, we can't check the file size.
        if (
          contentLength &&
          parseInt(contentLength) >= uncompressedFileSize &&
          process.env.NODE_ENV !== 'development'
        ) {
          warn(
            `The WASM binary file is being served without compression. Due to its size, it's recommended to configure the server so application/wasm files are served with compression.

Find more details in our Standalone performance guides: https://pspdfkit.com/guides/web/best-practices/caching-on-the-web/#gzip-and-brotli`,
          )
        }

        return response
      })
      .catch(error => {
        throw new Error(`Failed to load WASM binary file: ${error}`)
      })

    module['instantiateWasm'] = (
      imports: any,
      successCallback: (instance: any, module: any) => void,
    ) => {
      ;(async () => {
        /* eslint-disable */
        log(`Start ${module.wasmBinaryFile} download.`)
        const t1 = Date.now()
        let instantiatePromise, t2
        const isInstantiateStreamingSupported =
          !disableWebAssemblyStreaming && typeof WebAssembly.instantiateStreaming == 'function'

        function instantiateWithoutStreaming() {
          return fetchPromise
            .then(r => {
              if (!r.ok) {
                throw new Error(`Error loading ${module.wasmBinaryFile}: ${r.statusText}`)
              }

              return r.arrayBuffer()
            })
            .then(wasmBinary => {
              t2 = Date.now()
              log(`Download complete, took: ${t2 - t1}ms`)
              return WebAssembly.instantiate(new Uint8Array(wasmBinary), imports)
            })
        }

        if (isInstantiateStreamingSupported) {
          instantiatePromise = WebAssembly.instantiateStreaming(fetchPromise, imports)
            .then(output => {
              t2 = Date.now()
              log(`Download and Instantiation complete, took: ${Date.now() - t1}ms`)
              return output
            })
            .catch(e => {
              if (/mime.*type/i.test(e.message)) {
                error(e.message)
                return null
              }

              throw e
            })
        } else {
          instantiatePromise = instantiateWithoutStreaming()
        }

        let output = await instantiatePromise

        if (output === null) {
          error(
            'Streaming instantiation failed! ' +
              'Falling back to classic instantiation. ' +
              'This might result in slower initialization time ' +
              'therefore we highly recommend to follow ' +
              'the troubleshooting instructions in our guides to fix this error: https://pspdfkit.com/guides/web/current/troubleshooting/common-issues/#response-has-unsupported-mime-type-error.',
          )
          output = await instantiateWithoutStreaming()
        }

        if (!isInstantiateStreamingSupported && t2) {
          log(`Compilation and Instantiation complete, took: ${Date.now() - t2}ms`)
        }

        successCallback(output.instance, output.module)
        /* eslint-enable */
      })()

      return {}
    }
  }

  return module
}

