import { PSPDFKitError } from '@pspdfkit/shared'

import type { DynamicFonts } from '@/models/DynamicFonts'

export async function downloadDynamicFontsFile(dynamicFonts: string): Promise<Response> {
  try {
    const res = await fetch(dynamicFonts).catch(error => {
      throw new PSPDFKitError(`Error fetching dynamic fonts file ${dynamicFonts}. ${error}`)
    })

    if (res.status !== 200) {
      throw new PSPDFKitError(
        `Error fetching dynamic fonts file ${dynamicFonts}. Status code: ${res.status}`,
      )
    }

    return res
  } catch (error) {
    throw error
  }
}

export async function downloadAndParseDynamicFontsFile(
  dynamicFonts: string,
): Promise<DynamicFonts> {
  const dynamicFontsJSON = (await downloadDynamicFontsFile(dynamicFonts)).json().catch(error => {
    throw new PSPDFKitError(`Error parsing dynamic fonts file ${dynamicFonts}. ${error}`)
  })

  return dynamicFontsJSON
}

/**
 * Returns if a given array buffer is a PKCS#7 cryptographic
 * structure. This function is intended as a fast heuristic, and may
 * return false positives in some cases.
 */
export function isPkcs7(signature: ArrayBuffer) {
  try {
    const uint8Array = new Uint8Array(signature)

    if (!uint8Array.length) {
      return false
    }

    // Check if it's potentially a PKCS#7 signature (the first byte is 0x30).
    if (uint8Array[0] === 0x30) {
      return true
    }

    return false
  } catch (error) {
    throw new Error(`Error checking if the signature is in PKCS#7 format: ${error.message}`)
  }
}
