/**
 * Determine the current browser engine.
 *
 * Based on Rendering Engine from:
 * https://developer.mozilla.org/en-US/docs/Browser_detection_using_the_user_agent
 *
 * Order is relevant here:
 * 1. IE identifies as Trident/
 * 2. Edge identifies as Edge/, AppleWebKit/ and Chrome/
 * 3. Blink (Chrome and Opera) identifies as AppleWebKit/ and Chrome/
 */
export type EngineType = 'trident' | 'edge' | 'blink' | 'webkit' | 'gecko' | 'unknown'

export function _engine(ua: string = globalThis.navigator?.userAgent ?? ''): EngineType {
  if (ua.indexOf('Trident/') > -1) {
    return 'trident'
  } else if (ua.indexOf('Edge/') > -1) {
    return 'edge'
  } else if (ua.indexOf('Chrome/') > -1) {
    return 'blink'
  } else if (ua.indexOf('AppleWebKit/') > -1) {
    return 'webkit'
  } else if (ua.indexOf('Gecko/') > -1) {
    return 'gecko'
  } else {
    return 'unknown'
  }
}

/**
 * Search inside the user agent for a value like ` Trident/70.0` and returns
 * the major version.
 */
function extractFromUA(ua: string, identifier: string): number {
  const regexp = new RegExp(` ${identifier}/(\\d+)\\.*`)
  let match

  if ((match = ua.match(regexp))) {
    return Number(match[1])
  } else {
    return 0
  }
}

/**
 * Tries to find the version of the current engine. If none is found, `0` is returned.
 */
export function _engineVersion(ua: string = globalThis.navigator?.userAgent): number {
  switch (_engine(ua)) {
    case 'trident':
      return extractFromUA(ua, 'Trident')

    case 'edge':
      return extractFromUA(ua, 'Edge')

    case 'blink':
      return extractFromUA(ua, 'Chrome')

    case 'webkit':
      return extractFromUA(ua, 'Version')

    case 'gecko':
      return extractFromUA(ua, 'Firefox')

    default:
      return 0
  }
}

export type SystemType = 'windows' | 'ios' | 'macos' | 'android' | 'linux' | 'unknown'

export function _system(
  ua: string = globalThis.navigator?.userAgent ?? '',
  platform: string = globalThis.navigator?.platform ?? '',
  maxTouchPoints: number = globalThis.navigator?.maxTouchPoints ?? 0,
): SystemType {
  // This is an iOS device pretending to be a mac, if it reports it self as a
  // Intel mac with a multi-touch screen then we know no such Mac exists and thus it's a
  // iOS device.
  //
  if (platform.indexOf('MacIntel') > -1 && maxTouchPoints > 1) {
    return 'ios'
  } else if (ua.indexOf('Win') > -1) {
    return 'windows'
  } else if (ua.indexOf('iPhone') > -1 || ua.indexOf('iPad') > -1) {
    return 'ios'
    // iPad simulator may only report as iPad and not as MacIntel,
    // without iPad or iPhone mentions in UserAgent.
  } else if (platform === 'iPad') {
    return 'ios'
  } else if (ua.indexOf('Mac') > -1) {
    return 'macos'
  } else if (ua.indexOf('Android') > -1) {
    return 'android'
  } else if (ua.indexOf('Linux') > -1) {
    return 'linux'
  } else {
    return 'unknown'
  }
}

export function _isSupportedMobileOS(
  system: SystemType = _system(),
  engine: EngineType = _engine(),
): boolean {
  return system === 'ios' || system === 'android' || isIPadOS(engine)
}

function safariVersion(ua: string = globalThis.navigator?.userAgent ?? ''): number {
  const match = ua.match(/Version\/(\d+\.\d)/)

  if (match) {
    return Number(match[1])
  }

  return 0
}

export const engine = _engine()

export const system = _system()

export const engineVersion = _engineVersion()

export const isSupportedMobileOS = _isSupportedMobileOS()

export const isSafari = engine === 'webkit'

export const isFirefox = engine === 'gecko'

export const isChrome = engine === 'blink'

export const isIE11 = engine === 'trident'

export const isLegacyEdge = engine === 'edge'

export const isMobileSafari = system === 'ios' || isIPadOS()

export const isAndroid = system === 'android'

export const isChromeAndroid = isChrome && isAndroid

export const isIOS = system === 'ios'

export function isIPadOS(engine: EngineType = _engine()): boolean {
  if (typeof window !== 'undefined' && (window as any).PSPDFKIT_PLAYWRIGHT_TEST) {
    // In case of e2e tests webkit is detected as iPadOS so
    // we explicitly return false for it to avoid this false detection.

    return false
  }

  if (process.env.NODE_ENV !== 'production') {
    // jsdom identifies as webkit by default and has a TouchEvent constructor.
    // Right now all unit tests expect these tests to not be a valid mobile OS
    // so we bail out instead.
    if (globalThis.navigator?.userAgent.indexOf('jsdom/') >= 0) {
      return false
    }
  }

  return engine === 'webkit' && typeof TouchEvent !== 'undefined'
}

let isTouch

export function isTouchDevice() {
  if (typeof isTouch === 'undefined') {
    // navigator.maxTouchPoints() is not supported in Safari 13.1 and iOS Safari 13.4-13.7
    isTouch = 'ontouchstart' in window || globalThis.navigator?.maxTouchPoints > 0
  }

  return isTouch
}

if (typeof window !== 'undefined') {
  // If a mouse is detected, we prioritize it for the DocumentComparison UI.
  window.addEventListener('mousemove', function onMouseMove() {
    isTouch = false
    window.removeEventListener('mousemove', onMouseMove)
  })

  window.addEventListener('pointermove', function onPointerMove(event) {
    if (event.pointerType === 'mouse' || event.pointerType === 'pen') {
      isTouch = false
    }

    window.removeEventListener('pointermove', onPointerMove)
  })
}

export const isMac = /Mac/i.test(globalThis.navigator?.platform)

export const isSafariOlderThan = (version: number) => isSafari && safariVersion() < version
