import type { MeasurementValueConfiguration } from '@/models/measurements/MeasurementValueConfigurationCallback'

/*
[TODO: Mahmoud, figure out why this happens!]
Separating this util from the rest of `measurements` utils as this is used in Core.ts,
and for some reason importing `utils/measurements.ts` fails to build the project.
 */
export function transformScaleToCoreFormat(scale: MeasurementValueConfiguration) {
  return {
    name: scale.name,
    scale: {
      unitFrom: scale.scale.unitFrom,
      unitTo: scale.scale.unitTo,
      from: Number(scale.scale.fromValue),
      to: Number(scale.scale.toValue),
    },
    precision: scale.precision,
  }
}
