/**
 * We have custom wrappers for console methods so that UWP and other builds can build custom error
 * handling solutions on top of that.
 */

export function deprecation(message: string): void {
  warn(message)
}

export function deprecatedFunction(
  deprecatedFunction: string,
  replacementFunction: string,
  isNotAFunction?: boolean,
) {
  if (isNotAFunction) {
    return deprecation(
      `The API ${deprecatedFunction} has been deprecated and will be removed in the next major release. ` +
        `Please use ${replacementFunction} instead. ` +
        'Please go to https://pspdfkit.com/api/web/ for more informations',
    )
  }

  deprecation(
    `The function ${deprecatedFunction} was deprecated and will be removed in future version. ` +
      `Please use ${replacementFunction} instead.`,
  )
}

export function log(message: string): void {
  console.log(message) // eslint-disable-line no-console
}

export function warn(...args: string[]): void {
  console.warn(...args) // eslint-disable-line no-console
}

export function error(messageOrError: string | Error): void {
  console.error(messageOrError) // eslint-disable-line no-console
}

export function info(...args: string[]): void {
  console.info(...args) // eslint-disable-line no-console
}
